import fs from 'node:fs/promises'
import path from 'node:path'
import process from 'node:process'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const repoRoot = path.resolve(__dirname, '..')
const entryPath = path.join(repoRoot, 'preload', 'entry.js')
const outputPath = path.join(repoRoot, 'preload.js')

const LOCAL_REQUIRE_PATTERN = /\brequire\((['"])(\.{1,2}\/[^'"]+)\1\)/g

function toModuleId(filePath) {
  return path.relative(repoRoot, filePath).split(path.sep).join('/')
}

function indentBlock(source, indent) {
  return source
    .split('\n')
    .map(line => `${indent}${line}`)
    .join('\n')
}

async function resolveLocalModule(fromPath, request) {
  const basePath = path.resolve(path.dirname(fromPath), request)
  const candidates = [
    basePath,
    `${basePath}.js`,
    path.join(basePath, 'index.js')
  ]

  for (const candidate of candidates) {
    try {
      const stats = await fs.stat(candidate)
      if (stats.isFile()) return candidate
    } catch {
      // continue
    }
  }

  throw new Error(`Unable to resolve preload module "${request}" from ${fromPath}`)
}

async function collectModules(entryFilePath) {
  const orderedModules = []
  const seenFilePaths = new Set()

  async function visit(filePath) {
    const normalizedFilePath = path.resolve(filePath)
    if (seenFilePaths.has(normalizedFilePath)) return
    seenFilePaths.add(normalizedFilePath)

    const rawSource = await fs.readFile(normalizedFilePath, 'utf8')
    const source = rawSource.replace(/\r\n/g, '\n')
    const localRequires = [...source.matchAll(LOCAL_REQUIRE_PATTERN)]

    for (const match of localRequires) {
      const dependencyPath = await resolveLocalModule(normalizedFilePath, match[2])
      await visit(dependencyPath)
    }

    orderedModules.push({
      filePath: normalizedFilePath,
      moduleId: toModuleId(normalizedFilePath),
      source
    })
  }

  await visit(entryFilePath)
  return orderedModules
}

function renderBundle(modules) {
  const entryModuleId = toModuleId(entryPath)
  const renderedModules = modules
    .map(({ moduleId, source }) => {
      const annotatedSource = `${source}\n//# sourceURL=wordz-preload://${moduleId}`
      return `  ${JSON.stringify(moduleId)}: function (module, exports, require, __filename, __dirname) {\n${indentBlock(annotatedSource, '    ')}\n  }`
    })
    .join(',\n')

  return `// Auto-generated by scripts/build-preload-bundle.mjs. Do not edit directly.
const { contextBridge, ipcRenderer } = require('electron')

const __WORDZ_PRELOAD_MODULES = {
${renderedModules}
}

const __WORDZ_PRELOAD_CACHE = Object.create(null)

function __normalizePreloadBundlePath(value) {
  const parts = []
  for (const part of String(value || '').split('/')) {
    if (!part || part === '.') continue
    if (part === '..') {
      parts.pop()
      continue
    }
    parts.push(part)
  }
  return parts.join('/')
}

function __resolvePreloadBundleRequest(fromId, request) {
  if (!request.startsWith('./') && !request.startsWith('../')) return request
  const parentParts = fromId.split('/')
  parentParts.pop()
  return __normalizePreloadBundlePath(parentParts.concat(request.split('/')).join('/')) + '.js'
}

function __loadPreloadBundleModule(moduleId) {
  if (__WORDZ_PRELOAD_CACHE[moduleId]) {
    return __WORDZ_PRELOAD_CACHE[moduleId].exports
  }

  const factory = __WORDZ_PRELOAD_MODULES[moduleId]
  if (typeof factory !== 'function') {
    throw new Error(\`module not found: \${moduleId}\`)
  }

  const module = { exports: {} }
  __WORDZ_PRELOAD_CACHE[moduleId] = module
  const dirnameParts = moduleId.split('/')
  dirnameParts.pop()
  const dirname = dirnameParts.join('/') || '.'
  factory(module, module.exports, __createPreloadBundleRequire(moduleId), moduleId, dirname)
  return module.exports
}

function __createPreloadBundleRequire(fromId) {
  return function preloadBundleRequire(request) {
    const resolvedRequest = __resolvePreloadBundleRequest(fromId, request)
    if (resolvedRequest === request) {
      return require(request)
    }
    return __loadPreloadBundleModule(resolvedRequest)
  }
}

const __wordzPreloadEntry = __loadPreloadBundleModule(${JSON.stringify(entryModuleId)})
__wordzPreloadEntry.exposePreload({ contextBridge, ipcRenderer })
`
}

const modules = await collectModules(entryPath)
await fs.writeFile(outputPath, renderBundle(modules), 'utf8')
console.log(`Built preload bundle: ${path.relative(repoRoot, outputPath)}`)
